import React, { useEffect, useState } from 'react';
import { get, post, put, remove } from '../api';

const emptyGift = {
  name: '',
  imageUrl: '',
  isActive: true,
};

const isValidHttpUrl = (value) => {
  if (!value) {
    return true;
  }

  try {
    const parsed = new URL(value);
    return parsed.protocol === 'http:' || parsed.protocol === 'https:';
  } catch {
    return false;
  }
};

const GiftsList = () => {
  const [gifts, setGifts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [workingGift, setWorkingGift] = useState(emptyGift);
  const [editingId, setEditingId] = useState(null);
  const [actionError, setActionError] = useState(null);
  const [successMessage, setSuccessMessage] = useState(null);

  const loadGifts = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await get('/api/admin-lists/gifts');
      setGifts(response.data);
    } catch (err) {
      console.error(err);
      setError('Unable to load gifts.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadGifts();
  }, []);

  const handleRefresh = () => {
    loadGifts();
  };

  const handleEdit = (gift) => {
    setEditingId(gift.id);
    setWorkingGift({
      name: gift.name || '',
      imageUrl: gift.imageUrl || '',
      isActive: gift.isActive,
    });
  };

  const handleCreate = () => {
    setEditingId(null);
    setWorkingGift(emptyGift);
    setActionError(null);
    setSuccessMessage(null);
  };

  const handleSubmit = async () => {
    setActionError(null);
    setSuccessMessage(null);

    const trimmedName = workingGift.name.trim();
    const trimmedImageUrl = workingGift.imageUrl.trim();

    if (!trimmedName) {
      setActionError('Gift name is required.');
      return;
    }

    if (!isValidHttpUrl(trimmedImageUrl)) {
      setActionError('Image link must be a valid http/https URL.');
      return;
    }

    try {
      const payload = {
        ...workingGift,
        name: trimmedName,
        imageUrl: trimmedImageUrl,
      };

      if (editingId) {
        await put(`/api/admin-lists/gifts/${editingId}`, payload);
        setSuccessMessage('Gift updated successfully.');
      } else {
        await post('/api/admin-lists/gifts', payload);
        setSuccessMessage('Gift created successfully.');
      }
      await loadGifts();
      setEditingId(null);
      setWorkingGift(emptyGift);
    } catch (err) {
      console.error(err);
      setActionError('Unable to save gift.');
    }
  };

  const handleDelete = async (id) => {
    setActionError(null);
    setSuccessMessage(null);
    try {
      await remove(`/api/admin-lists/gifts/${id}`);
      setSuccessMessage('Gift deleted successfully.');
      await loadGifts();
    } catch (err) {
      console.error(err);
      setActionError('Unable to delete gift.');
    }
  };

  return (
    <div>
      <h2>Gift List</h2>
      <div style={{ marginBottom: 16 }}>
        <button onClick={handleRefresh} disabled={loading} style={{ marginRight: 8 }}>
          Refresh
        </button>
        <button onClick={handleCreate}>
          Add New Gift
        </button>
      </div>
      {successMessage && <p style={{ color: 'green' }}>{successMessage}</p>}
      {actionError && <p style={{ color: 'red' }}>{actionError}</p>}
      {loading && <p>Loading gifts...</p>}
      {error && <p style={{ color: 'red' }}>{error}</p>}
      {!loading && !error && (
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Gift</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Image Link</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Active</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {gifts.map((gift) => (
              <tr key={gift.id}>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{gift.name}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  {gift.imageUrl ? (
                    <div>
                      <div style={{ marginBottom: 6 }}>
                        <img
                          src={gift.imageUrl}
                          alt={gift.name}
                          style={{ width: 48, height: 48, objectFit: 'cover', borderRadius: 6, border: '1px solid #ddd' }}
                        />
                      </div>
                      <a href={gift.imageUrl} target="_blank" rel="noopener noreferrer">
                        Open
                      </a>
                    </div>
                  ) : (
                    'None'
                  )}
                </td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  {gift.isActive ? 'Yes' : 'No'}
                </td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  <button onClick={() => handleEdit(gift)} style={{ marginRight: 8 }}>
                    Edit
                  </button>
                  <button onClick={() => handleDelete(gift.id)}>Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
      <div style={{ marginTop: 24, maxWidth: 600 }}>
        <h3>{editingId ? 'Edit Gift' : 'Add Gift'}</h3>
        <div style={{ marginBottom: 8 }}>
          <label style={{ display: 'block', marginBottom: 4 }}>Gift</label>
          <input
            type="text"
            value={workingGift.name}
            onChange={(e) => setWorkingGift({ ...workingGift, name: e.target.value })}
            style={{ width: '100%', padding: 8 }}
          />
        </div>
        <div style={{ marginBottom: 8 }}>
          <label style={{ display: 'block', marginBottom: 4 }}>Image Link</label>
          <input
            type="text"
            value={workingGift.imageUrl}
            onChange={(e) => setWorkingGift({ ...workingGift, imageUrl: e.target.value })}
            placeholder="https://your-domain.com/gifts/pencil-set.jpg"
            style={{ width: '100%', padding: 8 }}
          />
          <div style={{ marginTop: 4, fontSize: 12, color: '#555' }}>
            Use an online image URL (http/https). The app stores the link, not the image file.
          </div>
        </div>
        {workingGift.imageUrl.trim() && (
          <div style={{ marginBottom: 12 }}>
            <div style={{ marginBottom: 4, fontSize: 12, color: '#555' }}>Preview</div>
            {isValidHttpUrl(workingGift.imageUrl.trim()) ? (
              <img
                src={workingGift.imageUrl.trim()}
                alt="Gift preview"
                style={{ width: 120, height: 120, objectFit: 'cover', borderRadius: 8, border: '1px solid #ddd' }}
                onError={(e) => {
                  e.currentTarget.style.display = 'none';
                }}
              />
            ) : (
              <div style={{ color: '#b91c1c', fontSize: 13 }}>Invalid image URL format.</div>
            )}
          </div>
        )}
        <div style={{ marginBottom: 8 }}>
          <label style={{ display: 'inline-flex', alignItems: 'center' }}>
            <input
              type="checkbox"
              checked={workingGift.isActive}
              onChange={(e) => setWorkingGift({ ...workingGift, isActive: e.target.checked })}
              style={{ marginRight: 8 }}
            />
            Active
          </label>
        </div>
        <button onClick={handleSubmit} style={{ marginRight: 8 }}>
          Save
        </button>
      </div>
    </div>
  );
};

export default GiftsList;
